package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.gewaarborgdloon;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElementVerwerker;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoon;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import lombok.AllArgsConstructor;

import java.math.BigDecimal;

@AllArgsConstructor
public abstract class AbstractGewaarborgdLoon implements GewaarborgdLoon {
    private ConstantManager constantManager;
    private LoonElementManager loonElementManager;
    private LoonElementVerwerker loonElementVerwerker;
    private Opper opper;
    private RekenTijd rekenTijd;

    public abstract Konstanten getKonstantenPercentageSupplement();

    public void berekenWeek2(
            Money bedragZiekte, BigDecimal tellerZiekteTweedeWeek, BigDecimal prestatieNoemer, GewoonLoon gewoonLoon,
            MoneyMap<AardKodeExtensie> carryoverMap) {

        if (tellerZiekteTweedeWeek.signum() > 0) {
            Money bedrag = berekenBedragVoorTeller(bedragZiekte, tellerZiekteTweedeWeek, prestatieNoemer);
            AardKodeExtensie looncodeZiekenkas = gewoonLoon.createGewaarborgdLoonZiekenkasZiekteTweedeWeek();

            BigDecimal percentageZiekenKas = constantManager.getActualConstant(Konstanten.KST_GEWAARB_LOON_ZIEKENKAS, rekenTijd).getProcentFactor();
            loonElementVerwerker.verwerkTotLoonElement(opper, loonElementManager, looncodeZiekenkas, bedrag.multiply(percentageZiekenKas), rekenTijd, carryoverMap);

            AardKodeExtensie looncodeSupplement = gewoonLoon.createGewaarborgdLoonSupplementZiekteTweedeWeek();
            Konstanten konstantenPercentageSupplement = getKonstantenPercentageSupplement();
            BigDecimal percentageSupplement = constantManager.getActualConstant(konstantenPercentageSupplement, rekenTijd).getProcentFactor();
            loonElementVerwerker.verwerkTotLoonElement(opper, loonElementManager, looncodeSupplement, bedrag.multiply(percentageSupplement), rekenTijd, carryoverMap);
        }
    }

    public void berekenWeek3En4(
            Money bedragZiekte, BigDecimal tellerZiekteWeek3En4, BigDecimal prestatieNoemer, GewoonLoon gewoonLoon,
            MoneyMap<AardKodeExtensie> carryoverMap) {
        if (tellerZiekteWeek3En4.signum() > 0) {
            Konstanten konstantenPercentageSupplement = getKonstantenPercentageSupplement();
            BigDecimal percentageSupplement = constantManager.getActualConstant(konstantenPercentageSupplement, rekenTijd).getProcentFactor();
            Money bedrag = bedragZiekte.multiply(tellerZiekteWeek3En4).multiply(percentageSupplement).divide(prestatieNoemer);
            AardKodeExtensie looncodeSupplement = gewoonLoon.createGewaarborgdLoonSupplementZiekteDerdeEnVierdeWeek();
            loonElementVerwerker.verwerkTotLoonElement(opper, loonElementManager, looncodeSupplement, bedrag, rekenTijd, carryoverMap);
        }
    }

    public static Money berekenBedragVoorTeller(Money bedrag, BigDecimal teller, BigDecimal noemer) {
        return bedrag.multiply(teller).divide(noemer);
    }
}
